from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            # Return a phrase that can follow the subject, e.g., "is American"
            low_obj = obj.lower()
            if low_obj in ("united states", "usa", "united states of america"):
                return "is American"
            # Simple heuristic: if object starts with "the ", drop it for adjective use
            if low_obj.startswith("the "):
                demonym = obj[4:].strip()
                return f"is {demonym}"
            # For other nationalities, just return the object itself (could be "Canadian")
            return f"is {obj}"
        if p == "occupation":
            return f"was a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut; describe crew membership in the mission
            return f"was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"operated by {obj}"
        if p == "commander":
            # Return just the astronaut's name; will be formatted in sentence builder
            return obj
        if p == "backuppilot":
            return obj
        if p == "crewmembers":
            return obj
        if p == "leader":
            # Subject is an entity, object is a person
            return f"{obj} is the leader of {subj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # Group triples by subject
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)

    sentences = []
    for subj, items in groups.items():
        # Separate crew‑related predicates from others
        crew_preds = {"commander", "backuppilot", "crewmembers"}
        crew_info = {"commander": [], "backuppilot": [], "crewmembers": []}
        other_items = []

        for t in items:
            if t.predicate.lower().replace(" ", "") in crew_preds:
                crew_info[t.predicate.lower().replace(" ", "")].append(t.object.strip().strip('"'))
            else:
                other_items.append(t)

        # Build sentence parts
        parts = []

        # Handle crew information if present
        crew_parts = []
        if crew_info["commander"]:
            crew_parts.append(f"commander {crew_info['commander'][0]}")
        if crew_info["backuppilot"]:
            crew_parts.append(f"backup pilot {crew_info['backuppilot'][0]}")
        if crew_info["crewmembers"]:
            crew_members = ", ".join(crew_info["crewmembers"])
            crew_parts.append(f"crew members {crew_members}")

        if crew_parts:
            parts.append(f"{subj} had " + ", ".join(crew_parts))

        # Handle other predicates
        if other_items:
            other_desc = [phrase(subj, t.predicate, t.object) for t in other_items]
            if len(other_desc) == 1:
                parts.append(f"{subj} {other_desc[0]}")
            else:
                body = ", ".join(other_desc[:-1])
                parts.append(f"{subj} {body}, and {other_desc[-1]}")

        # Combine parts for this subject
        if parts:
            sentences.append("; ".join(parts) + ".")

    # Combine sentences for different subjects
    return " ".join(sentences)

# EVOLVE-BLOCK-END

